@EventTarget
public void onPacketReceive(EventReceivePacket event) {
    if (event.getPacket() instanceof S18PacketEntityTeleport) {
        S18PacketEntityTeleport s18 = (S18PacketEntityTeleport) event.getPacket();
        int entityId = s18.getEntityId();
        double x = s18.getX() / 32.0;
        double y = s18.getY() / 32.0;
        double z = s18.getZ() / 32.0;
        float yaw = s18.getYaw() * 360 / 256.0f;
        float pitch = s18.getPitch() * 360 / 256.0f;

        // Update KillAura target position for aim prediction
        if (target != null && target.getEntityId() == entityId) {
            targetLastPos.set(x, y, z);
            targetLastRot.set(yaw, pitch);
        }

        // Update ESP render position
        entityPositions.put(entityId, new Vec3(x, y, z));
    }
}

