package net.minecraft.network.play.server;

import net.minecraft.network.Packet;
import net.minecraft.network.PacketBuffer;
import net.minecraft.network.play.INetHandlerPlayClient;
import java.io.IOException;

public class S18PacketEntityTeleport implements Packet<INetHandlerPlayClient> {
    private int entityId;
    private int posX, posY, posZ;
    private byte yaw, pitch;
    private boolean onGround;

    public S18PacketEntityTeleport() {}

    public void readPacketData(PacketBuffer buf) throws IOException {
        this.entityId = buf.readVarIntFromBuffer();
        this.posX = buf.readInt();
        this.posY = buf.readInt();
        this.posZ = buf.readInt();
        this.yaw = buf.readByte();
        this.pitch = buf.readByte();
        this.onGround = buf.readBoolean();
    }

    public void processPacket(INetHandlerPlayClient handler) {
        handler.handleEntityTeleport(this);
    }

    public int getEntityId() { return this.entityId; }
    public int getX() { return this.posX; }
    public int getY() { return this.posY; }
    public int getZ() { return this.posZ; }
    public byte getYaw() { return this.yaw; }
    public byte getPitch() { return this.pitch; }
    public boolean getOnGround() { return this.onGround; }
}

